    "utils/pdfGenerator.ts": r'''
import { jsPDF } from "jspdf";
import { GeneratedImage } from "../types";

// Helper to handle special characters for standard PDF fonts (which only support ASCII/Latin-1)
const sanitizeText = (str: string): string => {
  const map: { [key: string]: string } = {
    'ğ': 'g', 'Ğ': 'G',
    'ü': 'u', 'Ü': 'U',
    'ş': 's', 'Ş': 'S',
    'ı': 'i', 'İ': 'I',
    'ö': 'o', 'Ö': 'O',
    'ç': 'c', 'Ç': 'C',
  };
  return str.replace(/[ğĞüÜşŞıİöÖçÇ]/g, (match) => map[match]);
};

export const generatePDF = (childName: string, theme: string, images: GeneratedImage[], labels: any) => {
  const doc = new jsPDF({
    orientation: "portrait",
    unit: "mm",
    format: "a4"
  });

  const width = doc.internal.pageSize.getWidth();
  const height = doc.internal.pageSize.getHeight();

  // Sanitize inputs for PDF rendering
  const safeChildName = sanitizeText(childName);
  const safeTheme = sanitizeText(theme);
  const safeTitle = sanitizeText(labels.title);
  const safeSubtitle = sanitizeText(labels.forTemplate.replace('{name}', safeChildName));
  const safeThemeText = sanitizeText(labels.themeTemplate.replace('{theme}', safeTheme));
  const safeFooter = sanitizeText(labels.createdWith);

  // --- COVER PAGE DESIGN ---

  // Background color (very light gray/white)
  doc.setFillColor(252, 252, 252);
  doc.rect(0, 0, width, height, "F");

  // Decorative Border (Double Line)
  const margin = 15;
  doc.setDrawColor(79, 70, 229); // Indigo-600
  doc.setLineWidth(2);
  doc.rect(margin, margin, width - (margin * 2), height - (margin * 2), "S");

  doc.setDrawColor(165, 180, 252); // Indigo-200
  doc.setLineWidth(1);
  doc.rect(margin + 3, margin + 3, width - (margin * 2 + 6), height - (margin * 2 + 6), "S");

  // Title
  doc.setTextColor(30, 41, 59); // Slate-800
  doc.setFont("helvetica", "bold");
  doc.setFontSize(42);
  doc.text(safeTitle.toUpperCase(), width / 2, 50, { align: "center" });

  // Cover Image (Use the first generated image as a preview)
  if (images.length > 0) {
    const coverImg = images[0];
    const imgWidth = 120;
    const imgHeight = 160; // Aspect ratio 3:4
    const xPos = (width - imgWidth) / 2;
    const yPos = 70;

    // Draw a frame around the image
    doc.setDrawColor(30, 41, 59);
    doc.setLineWidth(0.5);
    doc.rect(xPos - 1, yPos - 1, imgWidth + 2, imgHeight + 2);

    doc.addImage(coverImg.base64, 'JPEG', xPos, yPos, imgWidth, imgHeight);
  }

  // "For [Name]"
  doc.setFont("helvetica", "bold");
  doc.setFontSize(24);
  doc.setTextColor(79, 70, 229); // Indigo Color
  doc.text(safeSubtitle, width / 2, 250, { align: "center" });

  // Theme Description with Word Wrap
  doc.setFont("helvetica", "normal");
  doc.setFontSize(14);
  doc.setTextColor(100, 116, 139); // Slate-500
  // Split text to ensure it doesn't overflow
  const splitTheme = doc.splitTextToSize(safeThemeText, width - 60);
  doc.text(splitTheme, width / 2, 265, { align: "center" });

  // Footer
  doc.setFontSize(10);
  doc.setTextColor(148, 163, 184);
  doc.text(safeFooter, width / 2, height - 25, { align: "center" });

  // --- CONTENT PAGES ---
  images.forEach((img, index) => {
    doc.addPage();

    // Reset border for content pages (Simple single border)
    doc.setDrawColor(0, 0, 0);
    doc.setLineWidth(0.5);

    // Maximize image size but keep aspect ratio
    const pageMargin = 20;
    const maxImgWidth = width - (pageMargin * 2);
    const maxImgHeight = height - (pageMargin * 2) - 20; // Space for footer

    doc.addImage(img.base64, 'JPEG', pageMargin, pageMargin, maxImgWidth, maxImgHeight, undefined, 'FAST');

    // Page number
    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
    doc.setTextColor(100, 100, 100);
    const pageText = `${labels.pagePrefix} ${index + 1}`;
    doc.text(sanitizeText(pageText), width / 2, height - 15, { align: "center" });
  });

  doc.save(`${safeChildName.replace(/\s+/g, '_')}_Coloring_Book.pdf`);
};''',

    "services/geminiService.ts": r'''
import { GoogleGenAI, Type, Schema, Chat } from "@google/genai";

let ai: GoogleGenAI | null = null;

const getAI = () => {
  if (!ai) {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API Key not found");
    }
    ai = new GoogleGenAI({ apiKey });
  }
  return ai;
};

// --- Image Generation Logic ---

export const generateCreativePrompts = async (theme: string): Promise<string[]> => {
  try {
    const client = getAI();
    // We instruct Gemini to output descriptions in English to ensure the image generator (Imagen) works optimally,
    // even if the user provides the theme in another language.
    const response = await client.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Generate 5 distinct, creative, and fun coloring book page descriptions for a children's book with the theme: "${theme}". 
      The descriptions must be in English, even if the theme is in another language.
      The descriptions should be visual, mentioning specific characters or scenes. 
      Keep them suitable for children.
      Ensure they are distinct from each other.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.STRING
          }
        } as Schema
      }
    });

    const text = response.text;
    if (!text) return [];

    try {
      return JSON.parse(text) as string[];
    } catch (e) {
      return [];
    }
  } catch (error) {
    console.error("GenAI Error (Prompts):", error instanceof Error ? error.message : "Unknown");
    throw new Error("Failed to contact AI service");
  }
};

export const generateColoringPageImage = async (description: string, style: string = 'cartoon'): Promise<string> => {
  try {
    const client = getAI();
    // Define style modifiers
    let stylePrompt = "";
    switch (style) {
      case 'realistic':
        stylePrompt = "realistic pencil sketch style, detailed fine lines, anatomical accuracy, naturalistic proportions";
        break;
      case 'mandala':
        stylePrompt = "mandala style, intricate geometric patterns, zentangle details, symmetry, meditative pattern";
        break;
      case 'pixel':
        stylePrompt = "pixel art style, 8-bit aesthetics, blocky edges, retro game style";
        break;
      case 'chibi':
        stylePrompt = "chibi style, super deformed, cute large heads, small bodies, kawai aesthetics";
        break;
      case 'anime':
        stylePrompt = "anime manga style, dynamic poses, expressive eyes, clean manga line art";
        break;
      case 'cartoon':
      default:
        stylePrompt = "clean thick distinct outlines, disney animation style, rounded shapes, simple details suitable for kids";
        break;
    }

    const finalPrompt = `A black and white children's coloring book page. ${stylePrompt}. Subject: ${description}. White background, high contrast, no shading, no grayscale filling, just clear line art, vector quality.`;

    const response = await client.models.generateImages({
      model: 'imagen-4.0-generate-001',
      prompt: finalPrompt,
      config: {
        numberOfImages: 1,
        outputMimeType: 'image/jpeg',
        aspectRatio: '3:4', 
      },
    });

    const base64Image = response.generatedImages?.[0]?.image?.imageBytes;
    if (!base64Image) throw new Error("No image generated");

    return `data:image/jpeg;base64,${base64Image}`;
  } catch (error) {
     console.error("GenAI Error (Image):", error instanceof Error ? error.message : "Unknown");
     throw error;
  }
};

// --- Chat Logic ---

let chatSession: Chat | null = null;

export const initializeChat = () => {
  try {
    const client = getAI();
    chatSession = client.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: "You are a friendly and enthusiastic assistant for a children's coloring book app called DreamColor. You help parents and kids come up with creative themes for their coloring books. You are encouraging, imaginative, and keep answers concise and helpful. You can speak English, Spanish, and Turkish. Detect the language the user is speaking and reply in that language. If the user's language is ambiguous, default to English.",
      }
    });
  } catch (e) {
    console.log("Chat init pending API key");
  }
};

export const sendMessageToChat = async (message: string): Promise<string> => {
  try {
    if (!chatSession) initializeChat();
    if (!chatSession) return "Please configure your API Key first.";

    const response = await chatSession.sendMessage({
      message: message
    });

    return response.text || "I couldn't think of a response, sorry!";
  } catch (error) {
    console.error("Chat Error", error instanceof Error ? error.message : "Unknown");
    return "I'm having trouble connecting right now.";
  }
};''',

    "components/Generator.tsx": r'''
import React, { useState, useRef } from 'react';
import { Download, Sparkles, Loader2, BookOpen } from 'lucide-react';
import { generateCreativePrompts, generateColoringPageImage } from '../services/geminiService';
import { generatePDF } from '../utils/pdfGenerator';
import { GeneratedImage, GenerationStatus, ArtStyle } from '../types';
import { useLanguage } from '../contexts/LanguageContext';

export const Generator: React.FC = () => {
  const { t } = useLanguage();
  const [theme, setTheme] = useState('');
  const [childName, setChildName] = useState('');
  const [artStyle, setArtStyle] = useState<ArtStyle>('cartoon');
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [progressMessage, setProgressMessage] = useState('');

  const lastGenerationTime = useRef<number>(0);
  const COOLDOWN_MS = 30000; // 30 seconds cooldown

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    // Rate limiting check
    const now = Date.now();
    if (now - lastGenerationTime.current < COOLDOWN_MS) {
      const remaining = Math.ceil((COOLDOWN_MS - (now - lastGenerationTime.current)) / 1000);
      setStatus(GenerationStatus.ERROR);
      setProgressMessage(`Please wait ${remaining} seconds before generating again.`);
      return;
    }

    if (!theme || !childName) return;

    setStatus(GenerationStatus.PLANNING);
    setGeneratedImages([]);
    setProgressMessage(t.header.planningMsg);
    lastGenerationTime.current = now;

    try {
      // Step 1: Generate prompts
      const prompts = await generateCreativePrompts(theme);

      if (prompts.length === 0) {
        throw new Error("Could not generate prompts. Please try a different theme.");
      }

      setStatus(GenerationStatus.GENERATING);

      const newImages: GeneratedImage[] = [];

      for (let i = 0; i < prompts.length; i++) {
        const progressMsg = t.header.drawingStatus
          .replace('{current}', (i + 1).toString())
          .replace('{total}', prompts.length.toString())
          .replace('{desc}', prompts[i].substring(0, 30));

        setProgressMessage(progressMsg);

        try {
          const base64 = await generateColoringPageImage(prompts[i], artStyle);
          const img: GeneratedImage = {
            id: crypto.randomUUID(),
            base64,
            prompt: prompts[i]
          };
          newImages.push(img);
          setGeneratedImages(prev => [...prev, img]);
        } catch (err) {
          console.error(`Failed to generate image ${i + 1}`);
        }
      }

      if (newImages.length > 0) {
        setStatus(GenerationStatus.COMPLETED);
      } else {
        setStatus(GenerationStatus.ERROR);
        setProgressMessage(t.header.noImages);
      }

    } catch (error) {
      console.error(error);
      setStatus(GenerationStatus.ERROR);
      setProgressMessage(t.header.error);
    }
  };

  const handleDownload = () => {
    if (generatedImages.length === 0) return;
    generatePDF(childName, theme, generatedImages, t.pdf);
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 md:p-8">

